Wondering if it also makes sense to expose something like this: in various languages just to get people started!
```js
export async function POST(req: Request): Promise<Response> {
  const { prompt, model } = await req.json();
  const systemMsg =
    `This is a system message`;
  const userMsg = `${prompt}`;
  const chatMessages = [
    { role: 'system', content: systemMsg },
    { role: 'user', content: userMsg },
  ];

  const controller = new AbortController();
  try {
    console.log('Starting local model request with messages:', chatMessages);
    const requestBody = {
      model: model, // You can replace this later dynamically
      messages: chatMessages,
      temperature: 0.9,
      max_tokens: 1000,
      stream: true, // for now this is a must in transformers
    };
    console.log('📤 Sending to local LLM:', requestBody);
    const response = await fetch('http://localhost:8000/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      signal: controller.signal,
      body: JSON.stringify(requestBody),
    });
    if (!response.ok || !response.body) {
      const errorText = await response.text();
      throw new Error(errorText);
    }
    return new Response(response.body, {
      status: response.status,
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Connection': 'keep-alive',
      },
    });
  } catch (err: any) {
    return new Response(err.message || 'Local model error', { status: 500 });
  }
}

```
and 
```js
const payload = {
